mapper.select:
select r.id, r.parent_id, p.region_name as parent_name, r.region_code, r.region_name, r.region_level, r.sort_no
from sys_region r
left join sys_region p on r.parent_id = p.id
where 1 = 1

    and r.region_level = #{regionLevel}


    and r.parent_id = #{parentId}


    and (r.region_name like concat('%', #{keyword}, '%')
    or r.region_code like concat('%', #{keyword}, '%'))

order by r.sort_no, r.id
limit #{offset}, #{limit}

select count(*) from sys_region where 1 = 1
and region_level = #{regionLevel}
and parent_id = #{parentId}
and (region_name like concat('%', #{keyword}, '%') or region_code like concat('%', #{keyword}, '%'))

mapper.update:
update sys_region
set parent_id = #{parentId},
    region_code = #{regionCode},
    region_name = #{regionName},
    region_level = #{regionLevel}
where id = #{id}

mapper.select:
select count(*)
from sys_region
where parent_id = #{parentId}

select
    (select count(*) from youth_info where deleted = 0 and (
        native_province_code = #{regionCode}
        or native_city_code = #{regionCode}
        or native_county_code = #{regionCode}
        or residence_province_code = #{regionCode}
        or residence_city_code = #{regionCode}
        or residence_county_code = #{regionCode}
        or school_province_code = #{regionCode}
        or school_city_code = #{regionCode}
        or school_county_code = #{regionCode}
    ))
    +
    (select count(*) from enterprise_info where deleted = 0 and (
        region_province_code = #{regionCode}
        or region_city_code = #{regionCode}
        or region_county_code = #{regionCode}
    ))
    +
    (select count(*) from job_post where deleted = 0 and (
        work_province_code = #{regionCode}
        or work_city_code = #{regionCode}
        or work_county_code = #{regionCode}
    ))
